        size = m.size ? ` ${(m.size/1024).toFixed(1)}KB` : '';
        src = m.source ? ` ← "${m.source.length > 30 ? m.source.slice(0,30)+'…' : m.source}"` : '';
        date = m.created ? ` ${new Date(m.created).toLocaleString()}` : '';
      } catch(e) {
        // Old format: plain mime string
        enc = 'raw'; mime = raw; src = '';
      }
    }
