      `<span style="color:#888">${c.slice(0,16)}…</span>` +
      `<span style="color:#666">${size} ${mime}</span>` +
      `<span style="color:#aa0">${date}</span>` +
      `<span style="color:#0aa">${src}</span></div>`;
  }).join('');
  set('ipfs-out', `${cids.length} blocks`);
};

